    async function refreshStaleAppCache() {
        try {
            const previous = localStorage.getItem(BUILD_STORAGE_KEY);
            localStorage.setItem(BUILD_STORAGE_KEY, BUILD_VERSION);
            if (!previous || previous === BUILD_VERSION)
                return false;
            if ("serviceWorker" in navigator) {
                const registrations = await navigator.serviceWorker.getRegistrations();
                await Promise.all(registrations.map(async (registration) => {
                    await registration.update().catch(() => null);
                }));
            }
            return false;
        }
        catch (error) {
            console.warn("App cache version check failed.", error);
            return false;
        }
    }
    /**
     * Force resetting PWA caches and reloading the page.
     * This helper will delete all caches and instruct service workers
     * to reset their internal caches. It only runs once per user based on
     * the FORCE_PWA_CACHE_RESET_FLAG. After running it reloads
     * the page so new parameters take effect.
     */
    async function forcePwaCacheResetIfNeeded() {
        try {
            const done = localStorage.getItem(FORCE_PWA_CACHE_RESET_FLAG);
            const buildMarker = localStorage.getItem("flashKanji.lastForcedBuild");
            if (done === "done" && buildMarker === BUILD_VERSION)
                return false;
            localStorage.setItem(FORCE_PWA_CACHE_RESET_FLAG, "done");
            localStorage.setItem("flashKanji.lastForcedBuild", BUILD_VERSION);
            return false;
        }
        catch (error) {
            console.warn("Force cache reset failed.", error);
            return false;
        }
    }
    async function loadCourse({ initialOnly = false } = {}) {
        const manifest = await fetchJson(DATA_URLS.lessons);
        const lessonsSource = Array.isArray(manifest?.lessons) ? manifest.lessons : [];
        const lessonsToLoad = initialOnly ? startupLessons(lessonsSource) : lessonsSource;
        const payloads = await mapInBatches(lessonsToLoad, async (lesson) => {
            try {
                return {
                    manifestLesson: lesson,
                    payload: await fetchJson(lesson.file)
                };
            }
            catch (error) {
                console.warn(`Skipping lesson data: ${lesson?.file || "unknown lesson file"}`, error);
                return null;
            }
        }, initialOnly ? lessonsToLoad.length : 3);
        const payloadByLessonId = new Map(payloads.filter(Boolean).map((entry) => [entry.manifestLesson.id, entry]));
        const lessons = lessonsSource.map((manifestLesson) => {
            const entry = payloadByLessonId.get(manifestLesson.id);
            if (!entry) {
                return {
                    ...manifestLesson,
                    file: manifestLesson.file,
                    items: []
                };
            }
            const { payload } = entry;
            return {
                ...manifestLesson,
                ...payload.lesson,
                file: manifestLesson.file,
                items: Array.isArray(payload.items) ? payload.items.map((item) => normalizeCard(item, payload.lesson.id)) : []
            };
        });
        const cards = lessons.flatMap((lesson) => lesson.items.map((item) => ({
            ...item,
            lessonTitle: lesson.title,
            lessonOrder: lesson.order
        })));
        return { lessons, cards };
    }
    function startupLessons(lessonsSource) {
        return lessonsSource.filter((lesson, index) => STARTUP_LESSON_IDS.has(lesson.id) || index < 2);
    }
    async function fetchJsonEntriesInBatches(entries, batchSize = 3) {
        const pairs = await mapInBatches(entries, async ([key, url]) => [key, await fetchJson(url)], batchSize);
        return Object.fromEntries(pairs);
    }
    async function mapInBatches(items, mapper, batchSize = 6) {
        const result = [];
        const size = Math.max(1, Number(batchSize) || 1);
        for (let index = 0; index < items.length; index += size) {
            const batch = items.slice(index, index + size);
            result.push(...await Promise.all(batch.map(mapper)));
            if (index + size < items.length) {
                await new Promise((resolve) => window.setTimeout(resolve, 0));
            }
        }
        return result;
    }
    async function fetchJson(url, fallback = null) {
        const candidates = buildJsonUrlCandidates(url);
        let lastError = null;
        for (const candidate of candidates) {
            try {
                const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
                const timeout = controller ? window.setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS) : 0;
                try {
                    const response = await fetch(candidate, {
                        cache: "no-store",
                        signal: controller?.signal
                    });
                    if (!response.ok) {
                        lastError = new Error(`Cannot load ${candidate}`);
                        continue;
                    }
                    const text = await response.text();
                    try {
                        return JSON.parse(text);
                    }
                    catch (parseError) {
                        lastError = parseError;
                        console.warn(`Invalid JSON from ${candidate}. Trying fallback paths.`, parseError);
                    }
                }
                finally {
                    if (timeout)
                        window.clearTimeout(timeout);
                }
            }
            catch (error) {
                lastError = error;
            }
        }
        console.warn(`Falling back to empty data for ${url}.`, lastError);
        if (typeof fallback === "function")
            return fallback(lastError);
        if (fallback !== null)
            return fallback;
        return {
            version: 1,
            languages: ["ru", "en"],
            ui: {},
            items: [],
            lessons: [],
            lesson: {},
            achievements: [],
            categories: []
        };
    }
    async function fetchText(url, fallback = "") {
        const candidates = buildJsonUrlCandidates(url);
        let lastError = null;
        for (const candidate of candidates) {
            try {
                const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
                const timeout = controller ? window.setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS) : 0;
                try {
                    const response = await fetch(candidate, {
                        cache: "no-store",
                        signal: controller?.signal
                    });
                    if (!response.ok) {
                        lastError = new Error(`Cannot load ${candidate}`);
                        continue;
                    }
                    return await response.text();
                }
                finally {
                    if (timeout)
                        window.clearTimeout(timeout);
                }
            }
            catch (error) {
                lastError = error;
            }
        }
        console.warn(`Falling back to empty text for ${url}.`, lastError);
        return typeof fallback === "function" ? fallback(lastError) : fallback;
    }
    function parseJlptReadingMarkdown(source) {
        const grouped = Object.fromEntries(LEVEL_ORDER.map((level) => [level, []]));
        const lines = String(source || "").split(/\r?\n/);
        let currentLevel = null;
        let currentItem = null;
        let mode = "idle";
        let codeLines = [];
        let questionLines = [];
        const flushItem = () => {
            if (!currentItem || !currentLevel)
                return;
            currentItem.text = trimMarkdownBlock(codeLines.join("\n"));
            currentItem.questions = questionLines.map((item) => item.trim()).filter(Boolean);
            grouped[currentLevel].push(currentItem);
            currentItem = null;
            codeLines = [];
            questionLines = [];
            mode = "idle";
        };
        const metaKeyFor = (value) => {
            const normalized = String(value || "").trim().toLowerCase();
            if (normalized === "жанр" || normalized === "genre")
                return "genre";
            if (normalized === "опора" || normalized === "source" || normalized === "basis")
                return "source";
            if (normalized === "цель" || normalized === "goal")
                return "goal";
            return normalized;
        };
        for (const rawLine of lines) {
            const line = String(rawLine ?? "");
            const trimmed = line.trim();
            const levelHeading = trimmed.match(/^#\s*JLPT\s*(N[1-5])\b/i);
            if (levelHeading) {
                flushItem();
                currentLevel = levelHeading[1].toUpperCase();
                continue;
            }
            const itemHeading = trimmed.match(/^##\s*(N[1-5])\s*(.+)$/i);
            if (itemHeading) {
                flushItem();
                currentLevel = itemHeading[1].toUpperCase();
                currentItem = {
                    id: `${currentLevel.toLowerCase()}-reading-${String((grouped[currentLevel] || []).length + 1).padStart(2, "0")}`,
                    level: currentLevel,
                    title: cleanJlptReadingTitle(itemHeading[2]),
                    genre: "",
                    source: "",
                    goal: "",
                    text: "",
                    questions: []
                };
                mode = "meta";
                continue;
            }
            if (/^#{1,2}(?!#)\s+/.test(trimmed) && !levelHeading && !itemHeading) {
                flushItem();
                currentLevel = null;
                continue;
            }
            if (!currentItem)
                continue;
            if (/^###\s*Проверочные вопросы/i.test(trimmed)) {
                mode = "questions";
                continue;
            }
            if (mode === "code") {
                if (/^```/.test(trimmed)) {
                    mode = "body";
                }
                else {
                    codeLines.push(line);
                }
                continue;
            }
            if (/^```/.test(trimmed)) {
                mode = "code";
                continue;
            }
            if (mode === "questions") {
                const bullet = trimmed.match(/^[-*]\s+(.*)$/);
                const numbered = trimmed.match(/^\d+\.\s+(.*)$/);
                if (bullet) {
                    questionLines.push(bullet[1]);
                    continue;
                }
                if (numbered) {
                    questionLines.push(numbered[1]);
                    continue;
                }
                if (!trimmed || /^---+$/.test(trimmed))
                    continue;
                questionLines.push(trimmed);
                continue;
            }
            const metaMatch = trimmed.match(/^\*\*(Жанр|Опора|Цель|Genre|Source|Goal)\:\*\*\s*(.*)$/i);
            if (metaMatch) {
                const key = metaKeyFor(metaMatch[1]);
                currentItem[key] = metaMatch[2].trim();
            }
        }
        flushItem();
        return grouped;
    }
    function trimMarkdownBlock(value) {
        return String(value || "")
            .replace(/^\s*\n+/, "")
            .replace(/\n+\s*$/, "");
    }
    function cleanJlptReadingTitle(value) {
        return String(value || "")
            .replace(/^[\s\-–—::]+/u, "")
            .trim();
    }
    function normalizeJlptReadingTranslations(payload) {
        const source = payload && typeof payload === "object" && !Array.isArray(payload)
            ? (payload.items && typeof payload.items === "object" && !Array.isArray(payload.items) ? payload.items : payload)
            : {};
        const result = {};
        Object.entries(source || {}).forEach(([id, item]) => {
            if (!id || !item || typeof item !== "object")
                return;
            result[String(id)] = {
                titleRu: String(item.titleRu || item.ruTitle || item.title_ru || "").trim(),
                titleEn: String(item.titleEn || item.enTitle || item.title_en || "").trim(),
                ru: String(item.ru || item.translationRu || item.translation_ru || "").trim(),
                en: String(item.en || item.translationEn || item.translation_en || "").trim()
            };
        });
        return result;
    }
    function buildJsonUrlCandidates(url) {
        const raw = String(url || "").trim();
        if (!raw)
            return [raw];
        if (/^https?:\/\//i.test(raw) || raw.startsWith("file:"))
            return [raw];
        const clean = raw.replace(/^\.\/+/, "").replace(/^\.\.\/+/, "").replace(/^\/+/, "");
        const candidates = [
            raw,
            `./${clean}`,
            `../${clean}`,
            `index/${clean}`,
            `/index/${clean}`,
            `/${clean}`
        ];
        return [...new Set(candidates.filter(Boolean))];
    }
    function normalizeCard(item, lessonId) {
        return {
            ...item,
            id: String(item.id),
            lessonId,
            examples: Array.isArray(item.examples) ? item.examples : [],
            apps: Array.isArray(item.apps) ? item.apps : [],
            stroke_order: Array.isArray(item.stroke_order) ? item.stroke_order : []
        };
    }
    function normalizeKanjiStrokeData(payload) {
        const items = payload?.items && typeof payload.items === "object" ? payload.items : {};
        return Object.fromEntries(Object.entries(items)
            .map(([kanji, item]) => {
            const strokeOrder = Array.isArray(item?.strokeOrder)
                ? item.strokeOrder.filter((stroke) => typeof stroke?.path === "string" && stroke.path.trim())
                : [];
            if (!strokeOrder.length)
                return null;
            return [kanji, {
                    ...item,
                    kanji: item.kanji || kanji,
                    strokes: Number(item.strokes || strokeOrder.length),
                    viewBox: item.viewBox || "0 0 109 109",
                    strokeOrder
                }];
        })
            .filter(Boolean));
    }
    function normalizeCustomizationCatalog(payload) {
        const categories = Array.isArray(payload?.categories) ? payload.categories : [];
        const items = Array.isArray(payload?.items) ? payload.items : [];
        return {
            version: Number(payload?.version || 1),
            currency: payload?.currency || "Moon Fragments",
            categories: categories.length ? categories : [
                { id: "all", title_ru: "Все", title_en: "All" },
                { id: "background", title_ru: "Фоны", title_en: "Backgrounds" },
                { id: "outfit", title_ru: "Образы", title_en: "Outfits" },
                { id: "decoration", title_ru: "Декор", title_en: "Decorations" },
                { id: "theme", title_ru: "Темы", title_en: "Themes" },
                { id: "effect", title_ru: "Эффекты", title_en: "Effects" }
            ],
            items: items.map((item) => ({
                ...item,
                id: String(item.id || ""),
                type: String(item.type || "effect"),
                price: Math.max(0, Number(item.price || 0)),
                rarity: String(item.rarity || "common").toLowerCase(),
                defaultOwned: Boolean(item.defaultOwned || item.price === 0),
                unlockCondition: item.unlockCondition || null
            })).filter((item) => item.id)
        };
    }
    function defaultCustomization() {
        return {
            owned: [],
            selected: {
                background: "bg_study_hub",
                outfit: "outfit_default_assassin",
                theme: "theme_default_dark",
                decoration: null,
                frame: null,
                effect: null
            },
            seen: [],
            updatedAt: new Date().toISOString()
        };
    }
    function readCustomizationStorage() {
        try {
            const raw = localStorage.getItem(CUSTOMIZATION_STORAGE_KEY);
            if (!raw)
                return defaultCustomization();
            const parsed = JSON.parse(raw);
            const base = defaultCustomization();
            return {
                owned: Array.isArray(parsed.owned) ? parsed.owned.map(String) : base.owned,
                selected: { ...base.selected, ...((parsed && parsed.selected) || {}) },
                seen: Array.isArray(parsed.seen) ? parsed.seen.map(String) : base.seen,
                updatedAt: parsed.updatedAt || base.updatedAt
            };
        }
        catch (error) {
            console.warn("Customization storage failed.", error);
            return defaultCustomization();
        }
    }
    function saveCustomizationStorage() {
        if (!state.customization)
            return false;
        if (customizationSaveQueued)
            return true;
        customizationSaveQueued = true;
        const run = () => {
            customizationSaveTimer = 0;
            customizationSaveQueued = false;
            state.customization.updatedAt = new Date().toISOString();
            try {
                localStorage.setItem(CUSTOMIZATION_STORAGE_KEY, JSON.stringify(state.customization));
            }
            catch (error) {
                console.warn("Customization save failed.", error);
            }
        };
        if ("requestIdleCallback" in window) {
            customizationSaveTimer = window.requestIdleCallback(run, { timeout: 1200 });
        }
        else {
            customizationSaveTimer = window.setTimeout(run, 160);
        }
        return true;
    }
    function flushPendingCustomizationState() {
        if (!state.customization)
            return false;
        customizationSaveQueued = false;
        if (customizationSaveTimer) {
            if ("cancelIdleCallback" in window)
                window.cancelIdleCallback(customizationSaveTimer);
            else
                window.clearTimeout(customizationSaveTimer);
            customizationSaveTimer = 0;
        }
        state.customization.updatedAt = new Date().toISOString();
        try {
            localStorage.setItem(CUSTOMIZATION_STORAGE_KEY, JSON.stringify(state.customization));
            return true;
        }
        catch (error) {
            console.warn("Customization save failed.", error);
            return false;
        }
    }
    function hydrateCustomization() {
        const customization = readCustomizationStorage();
        const owned = new Set();
        (customization.owned || []).forEach((id) => {
            const item = customizationShopItem(id) || legacyCustomizationItem(id);
            if (item)
                owned.add(item.id);
        });
        customizationShopItems().forEach((item) => {
            if (item.defaultOwned || item.price === 0)
                owned.add(item.id);
        });
        (state.progress.unlockedBackgrounds || []).forEach((id) => {
            const item = customizationShopItem(id) || legacyCustomizationItem(id);
            if (item)
                owned.add(item.id);
        });
        (state.progress.unlockedEvaSprites || []).forEach((sprite) => {
            const outfit = outfitItemBySprite(sprite);
            if (outfit)
                owned.add(outfit.id);
            if (state.progress.shop?.owned?.includes(`eva_sprite:${sprite}`) && outfit)
                owned.add(outfit.id);
        });
        (state.progress.shop?.owned || []).forEach((id) => {
            const legacyId = String(id);
            const item = customizationShopItem(legacyId) || legacyCustomizationItem(legacyId);
            if (item)
                owned.add(item.id);
            if (!item && legacyId.startsWith("eva_sprite:")) {
                const outfit = outfitItemBySprite(legacyId.replace("eva_sprite:", ""));
                if (outfit)
                    owned.add(outfit.id);
            }
        });
        const selected = normalizeCustomizationSelection({ ...defaultCustomization().selected, ...(customization.selected || {}) });
        if (state.progress.selectedEvaRoomBackground)
            selected.background = normalizeCustomizationItemId(state.progress.selectedEvaRoomBackground);
        if (state.progress.selectedEvaSprite)
            selected.outfit = outfitItemBySprite(state.progress.selectedEvaSprite)?.id || selected.outfit;
        if (!owned.has(selected.background))
            selected.background = "bg_study_hub";
        if (!owned.has(selected.outfit))
            selected.outfit = "outfit_default_assassin";
        if (!owned.has(selected.theme))
            selected.theme = "theme_default_dark";
        if (selected.decoration && !owned.has(selected.decoration))
            selected.decoration = null;
        if (selected.effect && !owned.has(selected.effect))
            selected.effect = null;
        state.customization = {
            owned: [...owned],
            selected,
            seen: [...new Set([...(customization.seen || []), ...owned])],
            updatedAt: customization.updatedAt || new Date().toISOString()
        };
        syncCustomizationToProgress();
        saveCustomizationStorage();
    }
    function syncCustomizationToProgress() {
        if (!state.customization || !state.progress)
            return;
        ensureEvaRoomProgress();
        const selected = state.customization.selected || {};
        if (selected.background)
            state.progress.selectedEvaRoomBackground = selected.background;
        const outfit = customizationShopItem(selected.outfit);
        if (outfit?.spriteId)
            state.progress.selectedEvaSprite = outfit.spriteId;
        state.progress.unlockedBackgrounds = [...new Set([
                ...(state.progress.unlockedBackgrounds || []),
                ...state.customization.owned.filter((id) => customizationShopItem(id)?.type === "background")
            ])];
        state.progress.unlockedEvaSprites = [...new Set([
                ...(state.progress.unlockedEvaSprites || []),
                ...state.customization.owned
                    .map((id) => customizationShopItem(id))
                    .filter((item) => item?.type === "outfit" && item.spriteId)
                    .map((item) => item.spriteId)
            ])];
        state.progress.shop ||= { owned: [], equipped: {} };
        state.progress.shop.owned = [...new Set([
                ...(state.progress.shop.owned || []),
                ...state.customization.owned,
                ...state.progress.unlockedEvaSprites.map((sprite) => `eva_sprite:${sprite}`)
            ])];
        state.progress.shop.equipped = {
            ...(state.progress.shop.equipped || {}),
            background: selected.background || null,
            outfit: selected.outfit || null,
            theme: selected.theme || null,
            decoration: selected.decoration || selected.frame || null,
            effect: selected.effect || null
        };
    }
    function customizationShopItems() {
        return state.customizationCatalog?.items || [];
    }
    function customizationShopItem(id) {
        return customizationShopItems().find((item) => item.id === id) || null;
    }
    function legacyCustomizationItem(id) {
        const legacyId = String(id || "");
        if (!legacyId)
            return null;
        return customizationShopItems().find((item) => Array.isArray(item.legacyIds) && item.legacyIds.map(String).includes(legacyId)) || null;
    }
    function normalizeCustomizationItemId(id) {
        const item = customizationShopItem(id) || legacyCustomizationItem(id);
        return item?.id || id || null;
    }
    function normalizeCustomizationSelection(selected = {}) {
        return {
            background: normalizeCustomizationItemId(selected.background),
            outfit: normalizeCustomizationItemId(selected.outfit),
            theme: normalizeCustomizationItemId(selected.theme),
            decoration: normalizeCustomizationItemId(selected.decoration || selected.frame),
            effect: normalizeCustomizationItemId(selected.effect)
        };
    }
    function outfitItemBySprite(sprite) {
        const spriteId = String(sprite || "");
        if (!spriteId)
            return null;
        const legacyToken = `eva_sprite:${spriteId}`;
        return customizationShopItems().find((item) => {
            if (item.type !== "outfit")
                return false;
            if (item.spriteId === spriteId)
                return true;
            if (item.legacySpriteId === spriteId)
                return true;
            return Array.isArray(item.legacyIds) && item.legacyIds.map(String).includes(legacyToken);
        }) || null;
    }
