            return value !== 0;
        if (typeof value === "string") {
            const normalized = value.trim().toLowerCase();
            if (["false", "0", "off", "no", "disabled"].includes(normalized))
                return false;
            if (["true", "1", "on", "yes", "enabled"].includes(normalized))
                return true;
        }
        return fallback;
