        const before = cloneProgress(textbookExerciseProgress(course, canonical, exercise) || defaultTextbookExerciseProgress(canonical, exercise.lessonId || "", exercise.id, exercise));
        const after = calculateNextProgress(before, correct ? "good" : "again");
