                grammarN2: "Грамматика N2",
                readingN2: "Чтение N2",
                listeningN2: "Аудирование N2",
                finalTest: "Финальный тест",
                studiedKanji: "Изучено",
                completedLessons: "Уроки",
                completedGrammar: "Грамматика",
                completedReading: "Чтение",
                completedListening: "Аудирование",
                reviews: "Повторения",
                difficult: "Сложные",
                srs: "Повторение",
                lessons: "уроков",
