            hydrateProgress();
            if (parsed.customization) {
                state.customization = {
                    ...defaultCustomization(),
                    ...parsed.customization,
                    selected: { ...defaultCustomization().selected, ...(parsed.customization.selected || {}) }
                };
                saveCustomizationStorage();
            }
            hydrateCustomization();
            syncUxSoundSettings();
            saveProgress();
            applyTheme();
            toast(t("import"));
