    function ensureAudioContext() {
        try {
            audioContext ||= new (window.AudioContext || window.webkitAudioContext)();
            if (audioContext.state === "suspended")
                void audioContext.resume().catch(() => null);
            return audioContext;
        }
        catch (error) {
            console.warn("Audio context unavailable.", error);
            return null;
        }
    }
    function uxSoundFallbackProfile(name) {
        const key = String(name || "").toLowerCase();
        if (key.includes("wrong") || key.includes("failed"))
            return { type: "triangle", frequencies: [180], duration: 0.22, peak: 0.12, interval: 0 };
        if (key.includes("correct") || key.includes("success"))
            return { type: "triangle", frequencies: [440, 554.37], duration: 0.18, peak: 0.11, interval: 0.09 };
        if (key.includes("level") || key.includes("achievement") || key.includes("reward") || key.includes("xp") || key.includes("moon") || key.includes("unlock"))
            return { type: "sine", frequencies: [523.25, 659.25, 783.99], duration: 0.26, peak: 0.1, interval: 0.08 };
        if (key.includes("close"))
            return { type: "square", frequencies: [260], duration: 0.12, peak: 0.08, interval: 0 };
        if (key.includes("open") || key.includes("button") || key.includes("click") || key.includes("tab") || key.includes("page"))
            return { type: "sine", frequencies: [320], duration: 0.09, peak: 0.08, interval: 0 };
        return { type: "sine", frequencies: [360], duration: 0.16, peak: 0.08, interval: 0 };
    }
    function playGeneratedUxTone(name) {
        const ctx = ensureAudioContext();
        if (!ctx)
            return false;
        try {
            const profile = uxSoundFallbackProfile(name);
            const now = ctx.currentTime + 0.01;
            profile.frequencies.forEach((frequency, index) => {
                const oscillator = ctx.createOscillator();
                const gain = ctx.createGain();
                oscillator.type = profile.type;
                oscillator.frequency.value = frequency;
                const start = now + profile.interval * index;
                gain.gain.setValueAtTime(0.0001, start);
                gain.gain.exponentialRampToValueAtTime(profile.peak, start + 0.02);
                gain.gain.exponentialRampToValueAtTime(0.0001, start + profile.duration);
                oscillator.connect(gain).connect(ctx.destination);
                oscillator.start(start);
                oscillator.stop(start + profile.duration + 0.02);
            });
            lastUxSoundAt = Date.now();
            return true;
        }
        catch (error) {
            console.warn("Fallback UX tone failed.", error);
            return false;
        }
    }
    window.FlashKanjiUxToneFallback = playGeneratedUxTone;
    function installAudioUnlockListeners() {
        const unlock = () => {
            const ctx = ensureAudioContext();
            if (ctx?.state === "suspended")
                void ctx.resume().catch(() => null);
        };
        ["pointerdown", "touchstart", "keydown", "mousedown"].forEach((eventName) => {
            document.addEventListener(eventName, unlock, { once: true, passive: true, capture: true });
        });
    }
    function playTone(kind) {
        if (!state.progress.settings.sound)
            return;
        if (soundManager()) {
            playUxSound(kind === "again" ? "answer_wrong" : "answer_correct");
            return;
        }
        try {
            const ctx = ensureAudioContext();
            if (!ctx)
                return;
            lastUxSoundAt = Date.now();
            const oscillator = ctx.createOscillator();
            const gain = ctx.createGain();
            const now = ctx.currentTime;
            oscillator.type = "triangle";
            oscillator.frequency.value = kind === "again" ? 180 : 480;
            gain.gain.setValueAtTime(0.0001, now);
            gain.gain.exponentialRampToValueAtTime(0.13, now + 0.015);
            gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.18);
            oscillator.connect(gain).connect(ctx.destination);
            oscillator.start(now);
            oscillator.stop(now + 0.2);
        }
        catch (error) {
            console.warn("Audio unavailable.", error);
        }
    }
    function playAchievementSound() {
        if (!state.progress.settings.sound)
            return;
        try {
            const ctx = ensureAudioContext();
            if (!ctx)
                return;
            lastUxSoundAt = Date.now();
            const now = ctx.currentTime;
            [523.25, 659.25, 783.99].forEach((frequency, index) => {
                const oscillator = ctx.createOscillator();
                const gain = ctx.createGain();
                oscillator.type = "sine";
                oscillator.frequency.value = frequency;
                const start = now + index * 0.08;
                gain.gain.setValueAtTime(0.0001, start);
                gain.gain.exponentialRampToValueAtTime(0.12, start + 0.02);
                gain.gain.exponentialRampToValueAtTime(0.0001, start + 0.24);
                oscillator.connect(gain).connect(ctx.destination);
                oscillator.start(start);
                oscillator.stop(start + 0.26);
            });
        }
        catch (error) {
            console.warn("Achievement sound unavailable.", error);
        }
    }
